/**
 * Defines where the element should appear vertically in the viewport.
 */
export const ScrollToBlock = {
    /**
     * Aligns the top of the element to the top of the viewport.
     */
    START: 'start',

    /**
     * Aligns the element to the vertical center of the viewport.
     */
    CENTER: 'center',

    /**
     * Aligns the bottom of the element to the bottom of the viewport.
     */
    END: 'end',

    /**
     * Scrolls the minimal distance necessary to bring the element into view.
     */
    NEAREST: 'nearest'
};
